Here are the public test cases for feature2_1_append_path_segments:
{
  "cases": [
    {
      "expected_output": "text=http://www.foo.com/a/nice/path/gong?zot=23&zut\npath=[\"a\",\"nice\",\"path\",\"gong\"]\nquery=[[\"zot\",\"23\"],[\"zut\",null]]\nfragment=\n",
      "input": {
        "feature": "path_append",
        "segments": [
          "gong"
        ],
