    {
      "expected_output": "text=http://www.foo.com/a/nice/path/gong%2Fdouble%2F?zot=23&zut\npath=[\"a\",\"nice\",\"path\",\"gong%2Fdouble%2F\"]\nquery=[[\"zot\",\"23\"],[\"zut\",null]]\nfragment=\n",
