        "feature": "path_append",
        "segments": [
          "gong/double/"
        ],
        "url": "http://www.foo.com/a/nice/path/?zot=23&zut"
      }
    }
  ],
  "description": "Append one or more literal path segments while preserving the existing query and fragment and escaping embedded separators."
}

