Here are the public test cases for feature2_3_resolve_relative_references:
{
  "cases": [
    {
      "expected_output": "text=http://www.foo.com/a/nice/path/click\npath=[\"a\",\"nice\",\"path\",\"click\"]\nquery=[]\nfragment=\nhost=www.foo.com\n",
      "input": {
        "base": "http://www.foo.com/a/nice/path/?zot=23&zut",
        "feature": "resolve_reference",
        "reference": "click"
      }
    },
    {
      "expected_output": "text=http://a/b/g\npath=[\"b\",\"g\"]\nquery=[]\nfragment=\nhost=a\n",
      "input": {
        "base": "http://a/b/c/d;p?q",
        "feature": "resolve_reference",
        "reference": "../g"
      }
    },
    {
      "expected_output": "text=http://g\npath=[]\nquery=[]\nfragment=\nhost=g\n",
      "input": {
        "base": "http://a/b/c/d;p?q",
        "feature": "resolve_reference",
        "reference": "//g"
      }
    }
  ],
  "description": "Resolve a relative reference against a base reference using standard dot-segment, query, fragment, and authority rules."
}

Here are the public test cases for feature3_1_encoded_query_updates:
{
  "cases": [
    {
      "expected_output": "text=http://www.foo.com/a/nice/path/?zot=23&zut&foo=bar\nquery=[[\"zot\",\"23\"],[\"zut\",null],[\"foo\",\"bar\"]]\nvalues=[\"bar\"]\n",
      "input": {
        "feature": "query_update",
        "get": "foo",
        "steps": [
          {
            "change": "add",
            "name": "foo",
            "value": "bar"
          }
        ],
        "url": "http://www.foo.com/a/nice/path/?zot=23&zut"
      }
    },
    {
      "expected_output": "text=http://www.foo.com/a/nice/path/?zot=99&zut\nquery=[[\"zot\",\"99\"],[\"zut\",null]]\nvalues=[\"99\"]\n",
      "input": {
        "feature": "query_update",
        "get": "zot",
        "steps": [
          {
            "change": "set",
            "name": "zot",
            "value": "99"
          }
        ],
        "url": "http://www.foo.com/a/nice/path/?zot=23&zut"
      }
    },
    {
      "expected_output": "text=http://www.foo.com/a/nice/path/?zut\nquery=[[\"zut\",null]]\n",
      "input": {
        "feature": "query_update",
        "steps": [
          {
            "change": "remove",
            "name": "zot"
          }
        ],
        "url": "http://www.foo.com/a/nice/path/?zot=23&zut"
      }
    }
  ],
  "description": "Add, set, and remove encoded query parameters while preserving ordering and valueless parameters."
}

