Here are the public test cases for feature4_2_normalize_references:
{
  "cases": [
    {
      "expected_output": "text=http://example.com/a/c\nscheme=http\nhost=example.com\npath=[\"a\",\"c\"]\nquery=[]\n",
      "input": {
        "feature": "normalize_reference",
        "url": "HTTP://EXAMPLE.COM:80/a/./b/../c"
      }
    },
    {
      "expected_output": "text=https://example.com/~user?q=A\nscheme=https\nhost=example.com\npath=[\"~user\"]\nquery=[[\"q\",\"A\"]]\n",
      "input": {
        "feature": "normalize_reference",
        "url": "https://EXAMPLE.COM:443/%7Euser?q=%41"
      }
    }
  ],
  "description": "Normalize references by canonicalizing scheme and host case, removing default ports, resolving dot segments, and normalizing safe escapes."
}

